from typing import List, Optional, Union, Literal, Protocol

def advanced_example(data: List[Union[int, str]], flag: Optional[bool] = None) -> Literal["ok", "fail"]:
    if flag is None:
        return "fail"
    if isinstance(data[0], int):
        return "ok"
    return "fail"

class Drawable(Protocol):
    def draw(self) -> None: ...

def render(obj: Drawable) -> None:
    obj.draw()
